SELECT AVG(recovery_rate) AS average_recovery_rate
   FROM flotation_data
   WHERE site_id = 2;

SELECT date, site_id, operator_id, recovery_rate
FROM flotation_data
WHERE recovery_rate > 85.0;

SELECT site_name, site_operational_since
FROM mining_sites
ORDER BY site_operational_since DESC;

SELECT operator_name, SUM(experience_years) AS total_experience
   FROM operators
   GROUP BY operator_name;

SELECT MIN(experience_years) AS min_experience
FROM operators
WHERE operator_role = 'Supervisor';

SELECT site_name, location, site_operational_since, site_capacity_tons_per_day
FROM mining_sites
ORDER BY site_capacity_tons_per_day DESC;

SELECT site_name, site_capacity_tons_per_day
FROM mining_sites
ORDER BY site_capacity_tons_per_day DESC;
